{
  "paperId": "c8eee9766f0968e8f1b1be0731bc70b85be0ac97",
  "title": "InjecAgent: Benchmarking Indirect Prompt Injections in Tool-Integrated Large Language Model Agents",
  "year": 2024,
  "openAccessPdf": {
    "url": "",
    "status": null,
    "license": null,
    "disclaimer": "Notice: Paper or abstract available at https://arxiv.org/abs/2403.02691, which is subject to the license by the author or copyright owner provided with this content. Please go to the source to verify the license and copyright information for your use."
  },
  "authors": [
    {
      "authorId": "2167027235",
      "name": "Qiusi Zhan"
    },
    {
      "authorId": "2406359930",
      "name": "Zhixiang Liang"
    },
    {
      "authorId": "2290021230",
      "name": "Zifan Ying"
    },
    {
      "authorId": "2266051282",
      "name": "Daniel Kang"
    }
  ],
  "abstract": "Recent work has embodied LLMs as agents, allowing them to access tools, perform actions, and interact with external content (e.g., emails or websites). However, external content introduces the risk of indirect prompt injection (IPI) attacks, where malicious instructions are embedded within the content processed by LLMs, aiming to manipulate these agents into executing detrimental actions against users. Given the potentially severe consequences of such attacks, establishing benchmarks to assess and mitigate these risks is imperative. In this work, we introduce InjecAgent, a benchmark designed to assess the vulnerability of tool-integrated LLM agents to IPI attacks. InjecAgent comprises 1,054 test cases covering 17 different user tools and 62 attacker tools. We categorize attack intentions into two primary types: direct harm to users and exfiltration of private data. We evaluate 30 different LLM agents and show that agents are vulnerable to IPI attacks, with ReAct-prompted GPT-4 vulnerable to attacks 24% of the time. Further investigation into an enhanced setting, where the attacker instructions are reinforced with a hacking prompt, shows additional increases in success rates, nearly doubling the attack success rate on the ReAct-prompted GPT-4. Our findings raise questions about the widespread deployment of LLM Agents. Our benchmark is available at https://github.com/uiuc-kang-lab/InjecAgent."
}

{
  "paperId": "9df0947ec8a14c43e69f3b72ece5e9af2b8e8215",
  "title": "Memory-R1: Enhancing Large Language Model Agents to Manage and Utilize Memories via Reinforcement Learning",
  "year": 2025,
  "openAccessPdf": {
    "url": "",
    "status": null,
    "license": null,
    "disclaimer": "Notice: Paper or abstract available at https://arxiv.org/abs/2508.19828, which is subject to the license by the author or copyright owner provided with this content. Please go to the source to verify the license and copyright information for your use."
  },
  "authors": [
    {
      "authorId": "2365440320",
      "name": "Sikuan Yan"
    },
    {
      "authorId": "2304711524",
      "name": "Xiufeng Yang"
    },
    {
      "authorId": "2203968754",
      "name": "Zuchao Huang"
    },
    {
      "authorId": "2197254657",
      "name": "Ercong Nie"
    },
    {
      "authorId": "2046761003",
      "name": "Zifeng Ding"
    },
    {
      "authorId": "2377740835",
      "name": "Zonggen Li"
    },
    {
      "authorId": "2301241265",
      "name": "Xiaowen Ma"
    },
    {
      "authorId": "2130001188",
      "name": "Hinrich Schutze"
    },
    {
      "authorId": "2271282409",
      "name": "Volker Tresp"
    },
    {
      "authorId": "2362602394",
      "name": "Yunpu Ma"
    }
  ],
  "abstract": "Large Language Models (LLMs) have demonstrated impressive capabilities across a wide range of NLP tasks, but they remain fundamentally stateless, constrained by limited context windows that hinder long-horizon reasoning. Recent efforts to address this limitation often augment LLMs with an external memory bank, yet most existing pipelines are static and heuristic-driven, lacking a learned mechanism for deciding what to store, update, or retrieve. We present Memory-R1, a reinforcement learning (RL) framework that equips LLMs with the ability to actively manage and utilize external memory through two specialized agents: a Memory Manager that learns structured operations, including ADD, UPDATE, DELETE, and NOOP; and an Answer Agent that pre-selects and reasons over relevant entries. Both agents are fine-tuned with outcome-driven RL (PPO and GRPO), enabling adaptive memory management with minimal supervision. With only 152 training QA pairs, Memory-R1 outperforms strong baselines and generalizes across diverse question types, three benchmarks (LoCoMo, MSC, LongMemEval), and multiple model scales (3B-14B)."
}

{
  "paperId": "79f2dcea1f249c62230f5483d0b08ebb775d6ca5",
  "title": "A Survey of Large Language Model Agents for Question Answering",
  "year": 2025,
  "openAccessPdf": {
    "url": "",
    "status": null,
    "license": null,
    "disclaimer": "Notice: Paper or abstract available at https://arxiv.org/abs/2503.19213, which is subject to the license by the author or copyright owner provided with this content. Please go to the source to verify the license and copyright information for your use."
  },
  "authors": [
    {
      "authorId": "2228468973",
      "name": "Murong Yue"
    }
  ],
  "abstract": "This paper surveys the development of large language model (LLM)-based agents for question answering (QA). Traditional agents face significant limitations, including substantial data requirements and difficulty in generalizing to new environments. LLM-based agents address these challenges by leveraging LLMs as their core reasoning engine. These agents achieve superior QA results compared to traditional QA pipelines and naive LLM QA systems by enabling interaction with external environments. We systematically review the design of LLM agents in the context of QA tasks, organizing our discussion across key stages: planning, question understanding, information retrieval, and answer generation. Additionally, this paper identifies ongoing challenges and explores future research directions to enhance the performance of LLM agent QA systems."
}

{
  "paperId": "61d18f878dcd6ee9af171e45e763af114e6eced4",
  "title": "Emergence of human-like polarization among large language model agents",
  "year": 2025,
  "openAccessPdf": {
    "url": "",
    "status": null,
    "license": null,
    "disclaimer": "Notice: Paper or abstract available at https://arxiv.org/abs/2501.05171, which is subject to the license by the author or copyright owner provided with this content. Please go to the source to verify the license and copyright information for your use."
  },
  "authors": [
    {
      "authorId": "10241302",
      "name": "J. Piao"
    },
    {
      "authorId": "2339424749",
      "name": "Zhihong Lu"
    },
    {
      "authorId": "2276188578",
      "name": "Chen Gao"
    },
    {
      "authorId": "3065590",
      "name": "Fengli Xu"
    },
    {
      "authorId": "2373646050",
      "name": "F. P. Santos"
    },
    {
      "authorId": "2334588999",
      "name": "Yong Li"
    },
    {
      "authorId": "2278792672",
      "name": "James Evans"
    }
  ],
  "abstract": "Rapid advances in large language models (LLMs) have not only empowered autonomous agents to generate social networks, communicate, and form shared and diverging opinions on political issues, but have also begun to play a growing role in shaping human political deliberation. Our understanding of their collective behaviours and underlying mechanisms remains incomplete, however, posing unexpected risks to human society. In this paper, we simulate a networked system involving thousands of large language model agents, discovering their social interactions, guided through LLM conversation, result in human-like polarization. We discover that these agents spontaneously develop their own social network with human-like properties, including homophilic clustering, but also shape their collective opinions through mechanisms observed in the real world, including the echo chamber effect. Similarities between humans and LLM agents -- encompassing behaviours, mechanisms, and emergent phenomena -- raise concerns about their capacity to amplify societal polarization, but also hold the potential to serve as a valuable testbed for identifying plausible strategies to mitigate polarization and its consequences."
}

{
  "paperId": "4233cf4e5eda6b32e9abc74ded5a2f8c67a59663",
  "title": "PersonaAgent: When Large Language Model Agents Meet Personalization at Test Time",
  "year": 2025,
  "openAccessPdf": {
    "url": "",
    "status": null,
